namespace Components;

public class ShippingInfo
{
    public string Name { get; set; } = "";
    public string Address { get; set; } = "";
    public string City { get; set; } = "";
    public string ZipCode { get; set; } = "";
}

public class PaymentInfo
{
    public string CardNumber { get; set; } = "";
    public string ExpiryDate { get; set; } = "";
}

public class Order
{
    public ShippingInfo Shipping { get; set; } = new();
    public PaymentInfo Payment { get; set; } = new();
}

@* Collects shipping address fields with basic validation *@

<div class="shipping-step">
    <h3>Shipping Information</h3>

    <label>
        Name
        <input value="@_shipping.Name"
               @onchange="e => _shipping.Name = e.Value?.ToString() ?? string.Empty" />
    </label>

    <label>
        Address
        <input value="@_shipping.Address"
               @onchange="e => _shipping.Address = e.Value?.ToString() ?? string.Empty" />
    </label>

    <label>
        City
        <input value="@_shipping.City"
               @onchange="e => _shipping.City = e.Value?.ToString() ?? string.Empty" />
    </label>

    <label>
        Zip Code
        <input value="@_shipping.ZipCode"
               @onchange="e => _shipping.ZipCode = e.Value?.ToString() ?? string.Empty" />
    </label>

    @if (!string.IsNullOrWhiteSpace(_validationMessage))
    {
        <p class="validation-error">@_validationMessage</p>
    }

    <button @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired]
    public ShippingInfo Shipping { get; set; } = default!;

    [Parameter]
    public EventCallback<ShippingInfo> OnNext { get; set; }

    private ShippingInfo _shipping = new();
    private string? _validationMessage;

    protected override void OnParametersSet()
    {
        // Copy parameter to private field to avoid mutating the parameter directly.
        _shipping = new ShippingInfo
        {
            Name = Shipping.Name,
            Address = Shipping.Address,
            City = Shipping.City,
            ZipCode = Shipping.ZipCode
        };
    }

    private async Task HandleNext()
    {
        if (string.IsNullOrWhiteSpace(_shipping.Name) || string.IsNullOrWhiteSpace(_shipping.Address))
        {
            _validationMessage = "Name and Address are required.";
            return;
        }

        _validationMessage = null;
        await OnNext.InvokeAsync(_shipping);
    }
}

@* Collects payment fields; provides Back and Place Order actions *@

<div class="payment-step">
    <h3>Payment Information</h3>

    <label>
        Card Number
        <input value="@_payment.CardNumber"
               @onchange="e => _payment.CardNumber = e.Value?.ToString() ?? string.Empty" />
    </label>

    <label>
        Expiry Date
        <input value="@_payment.ExpiryDate"
               @onchange="e => _payment.ExpiryDate = e.Value?.ToString() ?? string.Empty" />
    </label>

    <div class="payment-actions">
        <button @onclick="OnBack">Back</button>
        <button @onclick="HandlePlaceOrder">Place Order</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public PaymentInfo Payment { get; set; } = default!;

    [Parameter]
    public EventCallback OnBack { get; set; }

    [Parameter]
    public EventCallback<PaymentInfo> OnPlaceOrder { get; set; }

    private PaymentInfo _payment = new();

    protected override void OnParametersSet()
    {
        _payment = new PaymentInfo
        {
            CardNumber = Payment.CardNumber,
            ExpiryDate = Payment.ExpiryDate
        };
    }

    private async Task HandlePlaceOrder()
    {
        await OnPlaceOrder.InvokeAsync(_payment);
    }
}

@* Orchestrates the checkout steps and owns the Order state *@

<div class="checkout-wizard">
    @if (_step == Step.Shipping)
    {
        <ShippingStep Shipping="_order.Shipping" OnNext="HandleShippingNext" />
    }
    else if (_step == Step.Payment)
    {
        <PaymentStep Payment="_order.Payment"
                     OnBack="HandleBack"
                     OnPlaceOrder="HandlePlaceOrder" />
    }
</div>

@code {
    /// <summary>Raised when the user completes the checkout.</summary>
    [Parameter]
    public EventCallback<Order> OnOrderPlaced { get; set; }

    private Order _order = new();
    private Step _step = Step.Shipping;

    private enum Step { Shipping, Payment }

    private void HandleShippingNext(ShippingInfo shipping)
    {
        _order.Shipping = shipping;
        _step = Step.Payment;
    }

    private void HandleBack()
    {
        _step = Step.Shipping;
    }

    private async Task HandlePlaceOrder(PaymentInfo payment)
    {
        _order.Payment = payment;
        await OnOrderPlaced.InvokeAsync(_order);
    }
}

